#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int maxVal = -1, prefMaxCnt = 0;
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            if(i==0 || x>maxVal){
                maxVal = x;
                prefMaxCnt++;
            }
        }
        printf("%d\n", N - prefMaxCnt);
    }
    return 0;
}

