#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        max_val = -1
        pref_max_cnt = 0
        for i in range(N):
            x = next(it)
            if i == 0 or x > max_val:
                max_val = x
                pref_max_cnt += 1
        out_lines.append(str(N - pref_max_cnt))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

